MultiLanguageSpellData['nl'][465999] = {name = "Crimson Armored Growler", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Sommige Goblins noemen getrainde hyena's 'Growlers.' Deze is dol op graven.\"\nVerkoper:\nRocco Razzboom\nGebied:\nOndermijning\nKosten:\n8125"}
MultiLanguageSpellData['nl'][466000] = {name = "Darkfuse Chompactor", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Gezien de Top Dog onder Stix's Junkyard Hyenas, het heeft een beet kracht sterk genoeg om te verpletteren wat - of wie - Gallywix wil verwijderd.\"\nVerkoper:\nAndo de Gat\nGebied:\nBevrijding van Ondermijning\nKosten:\n500"}
MultiLanguageSpellData['nl'][466001] = {name = "Blackwater Bonecrusher", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Beste hou die botten voor jezelf als je ze niet verbrijzeld wilt hebben.\"\nDrop:\nBlackwater Trove\nGebied:\nOndermijning"}
MultiLanguageSpellData['nl'][466002] = {name = "Violet Armored Growler", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Smaks weet wel wat over hyena's. Regel nummer één: houd je handen weg van die tanden!\"\nVerkoper:\nSmaks Topskimmer\nGebied:\nOndermijning\nKosten:\n8125"}
