MultiLanguageSpellData['nl'][466011] = {name = "Flarendo de Furious", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"De VIP van VIP's in het Gallagio heeft zijn voordelen, inclusief de sleutels van deze voormalige koning van bloedbad. De geavanceerde goblin technologie stelt hem in staat om meer dan per gallon te bereiken!\"\nVerkoper:\nAndo de Gat\nGebied:\nBevrijding van Ondermijning\nKosten:\n777"}
MultiLanguageSpellData['nl'][466012] = {name = "Onweersbui", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Gevonden van de tribunes van de ketel tijdens een bijzonder gruwelijke botsing. Toen Torq gevraagd werd of het een blindganger was, antwoordde hij simpelweg: 'Waarschijnlijk?'\"\nVerkoper:\nAndo de Gat\nGebied:\nBevrijding van Ondermijning\nKosten:\n500"}
MultiLanguageSpellData['nl'][466013] = {name = "Ochre levering Raket", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Haal pakketten en passagiers van punt A naar B in stijl!\"\nVerkoper:\nShredz de Scrapper\nGebied:\nOndermijning\nKosten:\n11375"}
MultiLanguageSpellData['nl'][466014] = {name = "Steamwheedle Supplier", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Verbetert u met een snelle reis, of uw vijanden met een grote explosie!\"\nDrop:\nSteamwheedle Trove\nGebied:\nOndermijning"}
MultiLanguageSpellData['nl'][466016] = {name = "De Topskimmer Special", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Smaks weet zeker dat deze raket niet zal ontploffen tijdens de vlucht. Absoluut. Absoluut. Natuurlijk.\"\nVerkoper:\nSmaks Topskimmer\nGebied:\nOndermijning\nKosten:\n11375"}
MultiLanguageSpellData['nl'][466017] = {name = "Innovatieonderzoeker", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Wanneer het beste pad naar een goed idee is echt snel.\"\nVerkoper:\nSkedgit Cinderbangs\nGebied:\nOndermijning\nKosten:\n25"}
MultiLanguageSpellData['nl'][466018] = {name = "Donkerfuse-afbraakapparaat", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Uitstekend in het maken van een puinhoop van dingen. Niet zo goed in opruimen.\"\nVerkoper:\nSitch Lowdown\nGebied:\nOndermijning\nKosten:\n11375"}
MultiLanguageSpellData['nl'][466019] = {name = "Blackwater Shredder Deluxe Mk 2", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Beste niet te vragen wat er met Mk 1 is gebeurd.\"\nVerkoper:\nBoatswain HardeeZone:\nOndermijnCost:\n8125"}
MultiLanguageSpellData['nl'][466020] = {name = "Gepersonaliseerde Goblin SCRAPper", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Goblin Shredders hebben keer op keer bewezen nuttig te zijn in vele toepassingen, zoals in logging en transport. Dit model is opnieuw gebruikt door S.C.R.A.P.\"\nDrop:\nGezeefde Schroot\nGebied:\nOndermijning"}
MultiLanguageSpellData['nl'][466021] = {name = "Violet Goblin Shredder", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Deze versnipperaar is liefdevol geschilderd met een niet-corrosieve verf om een blijvende glans te garanderen.\"\nDrop:\nVerzending en verwerking\nGebied:\nOndermijning"}
