MultiLanguageSpellData['nl'][466023] = {name = "Asset Advocator", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Het verzekeren van anderen dat uw activa precies zijn waar ze moeten zijn.\"\nVerkoper:\nSkedgit CinderbangsZone:\nOndermijnCost:\n25"}
MultiLanguageSpellData['nl'][466024] = {name = "Bilgewater Bombardier", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Voor snel vervoer van Kartel handelsgoederen en andere zeer vluchtige stoffen.\"\nDrop:\nBilgewater Trove\nGebied:\nOndermijning"}
