MultiLanguageSpellData['nl'][467020] = {name = "Foute Zap", additional_info = "[q]Rik's machine korte circuits het verzenden van een schok van elektriciteit door verschillende spelers, waardoor Natuurschade. De elektriciteit blijft in hen, waardoor Natuurschade spelers binnen bereik en het verhogen van het doel Natuurschade genomen"}
MultiLanguageSpellData['nl'][467021] = {name = "Klauw Frenzy", additional_info = "[q]De caster gaat in een razernij, het toebrengen van Fysieke schade aan de vijand"}
MultiLanguageSpellData['nl'][467024] = {name = "Kaja'Cola Carrier", additional_info = "[q]Mislaid Curiosities hebben nu de kans om 1 Kaja'Cola te bevatten en eenmaal per delve roept Brann nu een Kaja'6-Pack op bij het creëren van kampvuren.\n\nEr zijn verschillende Kaja'Cola smaken, en elk heeft zijn eigen effect dat van toepassing is wanneer verzameld."}
MultiLanguageSpellData['nl'][467026] = {name = "Goblomagnetische bounzing grenade", additional_info = "[q]Brann heeft een kans tijdens de strijd om een GMB granaat te gooien op een vijandelijke doelwit dealen gematigde Natuurschade met een kans om Verdoving Dit heeft een kans om stuiteren naar een nieuw doel.\n\nDe granaat kan veilig op partijleden stuiteren."}
MultiLanguageSpellData['nl'][467029] = {name = "Impact Conversie Matrix", additional_info = "[q]Bij het invoeren van het gevecht, Brann activeert de conversiematrix Een klein percentage van alle partijschade behandeld gedurende deze tijd wordt omgezet in primaire stat en splitsen tussen partijleden.\n\nNa de conversie matrix powers down, de primaire status buff blijft Dit effect kan niet meer dan één keer optreden"}
