MultiLanguageSpellData['nl'][467033] = {name = "L00T RAID-R", additional_info = "FA00Elke 60 sec of 5 sec na het invoeren van de strijd, scan het milieu gemarkeerde vermiste nieuwsgierigheid en het maken van vijanden onder gezondheid nemen meer schade"}
MultiLanguageSpellData['nl'][467034] = {name = "Reverse Engineered Goblin Death Bomb", additional_info = "[q]Wanneer de gezondheid van een speler daalt tijdens het gevecht, Brann gooit een gigantische bom die explodeert bij impact.\n\nDe explosie Slaat terug en Vertraagt rondom vijanden en Heelt nabijgelegen partijleden van hun maximale gezondheid. Kan alleen voorkomen"}
MultiLanguageSpellData['nl'][467035] = {name = "Comisch Grote Magneet", additional_info = "[q]Wanneer Brann gebruik maakt van Gathering Tools, is er een kans om te magnetiseren verworpen Plating aan partijleden die hen van hun maximale gezondheid als een Schild die regenereert uit de strijd.\n\nVerzamelgereedschappen\nBrann gebruikt zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, leer en schatten te vinden."}
