MultiLanguageSpellData['nl'][467037] = {name = "Pinged Augment Chip", additional_info = "[q]Brann's maximale gezondheid is verhoogd en zijn schade en genezing gedaan is verhoogd.\n\nTerwijl in de strijd, Brann kan worden het doelwit door mechanische bots die fixeren op hem die kan worden vernietigd of Verdreven. Als ze Brann bereiken, zal hij lijden aan zijn maximale gezondheid in schade en Verdoofd"}
