MultiLanguageSpellData['nl'][470061] = {name = "Statische lading", additional_info = "[q]Torq's pak versterkt de elektrische ladingen gegenereerd binnen bereik. Tot de volgende Colossal Clash, een elektrische lading cursussen via spelers die in het bereik komen, waardoor Natuurschade Bovendien, terwijl in bereik, de lading groeit wanneer het doel beweegt en degradeert wanneer ze stationair. Bij maximale lading barst het uit in een Static Discharge."}
