MultiLanguageSpellData['nl'][470479] = {name = "Diabole ritueel", additional_info = "[q]Vernietiging\nCasting Chaos Bolt, Rain of Fire, of Shadowburn verleent Diabole Ritueel Als Diabole Ritueel al actief is, is de duur ervan verminderd sec in plaats daarvan.\n\nAls het duivelse ritueel afloopt, krijg je demonische kunst, waardoor je volgende Chaos Bolt, Rain of Fire, of Shadowburn een Overlord, Moeder van Chaos, of Pit Lord roept die een verwoestende aanval op je vijanden loslaat.\n\nDemonologie\nHet uitgeven van een Zielscherf op een schadelijke spreuk verleent Diabole Ritueel Terwijl Diabole Ritueel is actief, elke Zielscherf besteed aan een schadelijke spreuk vermindert de duur sec.\n\nAls het duivelse ritueel afloopt, krijg je demonische kunst, waardoor je volgende Hand van Gul'dan een Overlord, Moeder van Chaos, of Pit Heer roept die een verwoestende aanval op je vijanden loslaat."}
