MultiLanguageSpellData['nl'][470596] = {name = "Frostfire Burst", additional_info = "[q]Frost\nCasting Comet Storm zorgt ervoor dat uw volgende Ice Lance exploderen in een Frostfire Burst, dealen Frostfire schade aan nabijgelegen vijanden. Schade verminderd boven 8 doelen.\n\nFrostfire Burst heeft een kans om Brain Freeze te verlenen.\n\nVuur\nCasting Meteor zorgt ervoor dat uw volgende Vuur Blast exploderen in een Frostfire Burst, dealen Frostfire schade aan nabijgelegen vijanden. Schade verminderd boven 8 doelen.\n\nFrostfire Burst vermindert de cooldown van Phoenix Flames sec."}
