MultiLanguageSpellData['nl'][471359] = {name = "\"Goud\" Vis", additional_info = "[q]Hoewel zijn naam is een schattige indicator van de dikke gouden residu oneindig slijmen uit hun kieuwen, het is een anders ongemakkelijke herinnering van de Undermine's ongereguleerde industrialisatie.\n\nDeze vis is nu een onherkenbaar product van zijn milieu.\n\nSpeciaal:\n\nBlair Bass\n\nIn een poging om het ongerepte ondermijn ecosysteem te behouden, zou deze \"vis\" van groot belang zijn voor Blair Bass.\n\nGebieden die u kunt vinden deze vis:\n\n- Ondermijning.\n\nVisbaden:\n\n- Steamwheedle Runoff\nBeroep:\nVisserij"}
