MultiLanguageSpellData['nl'][471365] = {name = "Ondermijning", additional_info = "[q]Aanbevolen Vaardigheid: 375\n\nkanaliseert van Steamwheedle Runoff uit de verschillende pijpen. Het water wordt alleen bewoond door de sterkste Khaz Algar vis en wat er nog meer kan verdragen de scherpe vloeistof.\n\nZwembaden gevonden in deze zone:\n- Glimmerpool\n- Infused Ichor Spill\n- Steamwheedle Runoff\nBeroep:\nVisserij (225)"}
