MultiLanguageSpellData['nl'][471368] = {name = "Blair's \"Goud\" Fish Exchange", additional_info = "[q]Gelegen langs de centrale kanaliseren van The Vatworks, Blair Bass en haar team van Anglers hebben een speciale interesse genomen voor de lokale \"Goud\" Vis in de Undermine.\n\nKom langs om deel te nemen aan het behoud en verdien beloningen!\nBeroep:\nVisserij (225)"}
