MultiLanguageSpellData['nl'][471876] = {name = "Huil van de Pack Leader", additional_info = "[q]Beast Mastery\nTerwijl je in gevecht bent, roept je volgende Kill Command de hulp van een Beest op.\n\nWyvern\nEen Wyvern daalt af uit de lucht, laat een strijdkreet los die de schade van jou en je huisdieren verhoogt\n\nZwijn\nEen Boar laadt via uw doel 3 keer, dealen Fysieke schade aan het primaire doel en schade aan nabijgelegen vijanden.\n\nBeer\nEen Beer springt in de strijd, het vlees van je vijanden verscheurend, schade toebrengend aan nabijgelegen vijanden.\n\nOverleving\nTerwijl je in gevecht bent, roept je volgende Kill Command de hulp van een Beest op.\n\nWyvern\nEen Wyvern daalt af uit de lucht, laat een strijdkreet los die de schade van jou en je huisdieren verhoogt\n\nZwijn\nEen Boar laadt via uw doel 3 keer, dealen Fysieke schade aan het primaire doel en schade aan nabijgelegen vijanden.\n\nBeer\nEen Beer springt in de strijd, het vlees van je vijanden verscheurend, schade toebrengend aan nabijgelegen vijanden."}
