MultiLanguageSpellData['nl'][474572] = {name = "Optellen", additional_info = "[q]Mislaid Curiosities hebben nu de kans om 1 Kaja'Cola te bevatten en eenmaal per delve roept Brann nu een Kaja'6-Pack op bij het creëren van kampvuren.\n\nEr zijn verschillende Kaja'Cola smaken, en elk heeft zijn eigen effect dat van toepassing is wanneer verzameld.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474573] = {name = "Optellen", additional_info = "[q]Wanneer Brann gebruik maakt van Gathering Tools, is er een 100 % kans om te magnetiseren verworpen Plating aan partijleden die hen 5 % van hun maximale gezondheid als een Schild die regenereert uit de strijd.\n\nVerzamelgereedschappen\nBrann gebruikt zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, leer en schatten te vinden.\n\nJe hebt deze curio al in je collectie."}
