MultiLanguageSpellData['nl'][474576] = {name = "Optellen", additional_info = "[q]Het beschadigen van een Elite schepsel onder de 40 procent gezondheid creëert een onvolmaakte kopie van het op 50 % macht om te vechten aan uw zijde. Slechts 1 exemplaar kan tegelijkertijd bestaan.\n\nHet apparaat kan defect maken van onvolmaakte kopieën van uw metgezel.\n\nJe hebt deze curio al in je collectie."}
