MultiLanguageSpellData['nl'][474599] = {name = "Optellen", additional_info = "[q]Brann's Epic Egg herbergt nu 1 mechasaurs die vijanden voor (4000 / 1000) sec terwijl in het ei.\n\nMechasaurs zal periodiek stampen in aanvulling op hun gebruikelijke capaciteiten, dealen matige Vuurschade verdeeld tussen nabijgelegen vijanden. Getroffen vijanden ontploffen na 5 sec.\n\nBrann's epische ei\nBrann roept een duivelsaurus ei op. Hopelijk komt het uit.\n\nJe hebt deze curio al in je collectie."}
