MultiLanguageSpellData['nl'][474601] = {name = "Optellen", additional_info = "[q]Bij het invoeren van het gevecht, Brann activeert de conversiematrix Een klein percentage van alle partijschade behandeld gedurende deze tijd wordt omgezet in primaire stat en splitsen tussen partijleden.\n\nNa de conversie matrix powers down, de primaire status buff blijft Dit effect kan niet meer dan één keer optreden\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][474602] = {name = "Blastburn Roarcannon", additional_info = "[q]Flarendo volgt een doelwit tijdens het opladen, dan sluit op zijn plaats en bereidt zich voor om te vuren. Eenmaal klaar, vuurt het een straal over de volgende 3 seconden. De straal brengt Vuurschade aan spelers op contact, vernietigend hen."}
