MultiLanguageSpellData['nl'][1214849] = {name = "Leeg nest", additional_info = "[q]Beast Mastery, Survival\nInspireert uw huisdier om een vriendelijk doel te beschermen tegen kritische stakingen, het maken van aanvallen tegen dat doel niet in staat om kritische stakingen, maar van alle schade die door dat doel wordt genomen wordt ook genomen door het huisdier.\n\nMarkmanschap\nInspireert uw huisdier om een vriendelijk doelwit te beschermen tegen kritische stakingen, het maken van aanvallen tegen dat doel niet in staat om kritische stakingen te zijn.\n\nTerwijl Roar of Sacrifice actief is, kan je Spotting Eagle Spotter's Mark niet toepassen."}
