MultiLanguageSpellData['nl'][1215712] = {name = "Shaman Enhancement 11.1 Klasse Set 4pc", additional_info = "[q]Wanneer u uw winnende Streak verliezen! de winden verschuiven in Doom Wind Wanneer Doom Winds schade dealt, uw volgende Crash Lightning deals toegenomen schade,%. Dit effect kan worden opgeslagen stapels. Bovendien, Crash Lightning behandelt meer schade aan uw hoofddoel."}
