MultiLanguageSpellData['nl'][1215718] = {name = "Monk Windwalker 11.1 Klasse Set 4pc", additional_info = "[q]Fists of Furie is van toepassing 1 stapel winnende Streak! wanneer gegoten en wanneer klaar kanaliserend volledig. De schade van uw volgende Vuisten van Furie wordt verhoogd per stack wanneer winnende Streak! wordt verwijderd.\n\nUw winnende Streak! wordt altijd verwijderd zodra het bereikt max stacks."}
