MultiLanguageSpellData['nl'][1217987] = {name = "Combinatiebussen", additional_info = "[q]Gallywix tikt in zijn reserve voorraad schieten zowel Fused Canisters en Tick-Tock Canisters tegelijkertijd.\n\nNa 5 sec de Fused Canisters detoneren het veroorzaken van Vuurschade spelers binnen bereik, en na 6 sec de Tick-Tock Canisters detoneren het toebrengen van schade aan spelers binnen bereik. Deze effecten splitsten zich gelijkmatig onder spelers.\n\nAlle doelen raken getroffen door Mechengineer's Canisters.\n\nAls dit mislukt om ten minste 3 doelen te raken alle spelers lijden het volledige effect."}
MultiLanguageSpellData['nl'][1217990] = {name = "Geluk van de Draw!", additional_info = "[q]Als je geluk van de Draw!, uw volgende 2 casts van Blackout Kick deal toegenomen schade en een 2.0 sec gereduceerd cooldown."}
