MultiLanguageSpellData['nl'][1218305] = {name = "Gesmolten hengst", additional_info = "[q]Summons en ontslaat deze berg.\nFA00\"Gesmeed net als hun schoenen ooit waren, deze beesten zijn minder paarden nu en leeg Energie in hun gelijkenis.\"\nDrop:\nGebied:\nVision of Stormwind (herzien)"}
MultiLanguageSpellData['nl'][1218306] = {name = "Void-Scarred Pack Moeder", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Vechten tegen haar corrupte handlers deze roedel moeder bevrijdde zichzelf en haar pups. Vrijheid van hun verzorgers bevrijdde hen echter niet van de leegte in deze verloren plek. Ze leerde haar pups om nog gevaarlijker beesten te zijn, en ze stalken nu door heel Orgrimmar heen om haar voedsel te halen terwijl iedereen strijdt om te overleven.\"\nDrop:\nGebied:\nVision of Orgrimmar (herzien)"}
MultiLanguageSpellData['nl'][1218307] = {name = "Void-Scarred Windrider", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Toen de lege energieën werden vrijgegeven, reed het de meeste windrijders wild. Ze hebben elkaar en hun trainers vermoord. De poorten naar hun haan werden op slot gedaan door de overlevenden. Sommige overlevende windrijders zijn nog steeds te zien glijden boven, maar niemand durft terug te keren naar hun nieuwe dodelijke domein om te zien wat er overblijft.\"\nDrop:\nGebied:\nVision of Orgrimmar (herzien)"}
MultiLanguageSpellData['nl'][1218308] = {name = "Aanmaak Inferno", additional_info = "[q]Blazikon ontketent een vurige uitbarsting naar elke gedoofde kaars, reanimeren die kaars en het toebrengen van Vuurschade aan alle spelers op zijn pad.\n\nDe inferno sears alle spelers, het veroorzaken van Vuurschade Dit effect stacks."}
