MultiLanguageSpellData['nl'][1224964] = {name = "Optellen", additional_info = "[q]Brann dons Mana-tinted bril tijdens het gevecht, periodiek verhogen van zijn schade gedaan % en schade genomen % keer.\n\nVerdelen van de bril zal Heelt Brann voor 25 procent van zijn maximale gezondheid en Verdoving nabijgelegen vijanden\nAnders is dit effect automatisch Verdreven wanneer Brann daalt onder 30 procent gezondheid die voorkomt dat de Verdoving optreden.\n\nJe hebt deze curio al in je collectie."}
