MultiLanguageSpellData['nl'][1225038] = {name = "Twilight Devastation", additional_info = "[q]Toepassen Kleinere Rune van Twilight Devastation aan een roer.\n\nHiermee kunt u uw aanvallen hebben een kans om een straal van Twilight Devastation te activeren, dealen tot ( 1 * 845195 * 3) Schaduwschade aan vijanden voor u.\n\nKan niet worden toegepast op items onder niveau 350. Dit effect is vluchtig en zal alleen werken tijdens The War Within Season 2.\n(4s cooldown)"}
