MultiLanguageSpellData['nl'][1225061] = {name = "Optellen", additional_info = "[q]Wanneer Brann Gathering Tools gebruikt, begint zand te draaien rond partijleden, waarbij 6 % Critical Strike keer wordt toegekend en nabijgelegen vijanden worden vertraagd %.\n\nDealen van een Critical Strike creëert een Sand Devil op de locatie van het doel dat periodiek trekt vijanden naar het centrum. Kan alleen voorkomen\n\nVerzamelgereedschappen\nBrann gebruikt zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, leer en schatten te vinden.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225062] = {name = "Optellen", additional_info = "[q]Wanneer Brann Gathering Tools gebruikt, begint zand te draaien rond partijleden, waardoor 8 % Critical Strike keer en vertragen nabijgelegen vijanden %.\n\nDealen van een Critical Strike creëert een Sand Devil op de locatie van het doel dat periodiek trekt vijanden naar het centrum. Kan alleen voorkomen\n\nVerzamelgereedschappen\nBrann gebruikt zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, leer en schatten te vinden.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225063] = {name = "Optellen", additional_info = "[q]Wanneer Brann Gathering Tools gebruikt, begint zand te draaien rond partijleden, waardoor 10 % Critical Strike keer en vertragen nabijgelegen vijanden %.\n\nDealen van een Critical Strike creëert een Sand Devil op de locatie van het doel dat periodiek trekt vijanden naar het centrum. Kan alleen voorkomen\n\nVerzamelgereedschappen\nBrann gebruikt zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, leer en schatten te vinden.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225064] = {name = "Optellen", additional_info = "[q]Wanneer Brann Gathering Tools gebruikt, begint zand te draaien rond partijleden, waardoor 12 % Critical Strike keer en vertragen nabijgelegen vijanden %.\n\nDealen van een Critical Strike creëert een Sand Devil op de locatie van het doel dat periodiek trekt vijanden naar het centrum. Kan alleen voorkomen\n\nVerzamelgereedschappen\nBrann gebruikt zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, leer en schatten te vinden.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225065] = {name = "Optellen", additional_info = "[q]Het beschadigen van een Elite op 80 % of hoger en op 20 % of onder gezondheid veroorzaakt Brann om de energie van het kristal te activeren, het verminderen van de aanval van de Elite en cast Speed % Het doden van de doel Elite terwijl het debuff is actief verleent de partij een 2 % stapelen Haste buff.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225066] = {name = "Optellen", additional_info = "[q]Het beschadigen van een Elite op 80 % of hoger en op 20 % of onder gezondheid zorgt ervoor dat Brann de energieën van het kristal activeert, waardoor de Elite's aanval wordt verminderd en Speed % wordt gegoten Het doden van de doel Elite terwijl de debuff actief is verleent de partij een 4 % stapelen Haste buff.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225067] = {name = "Optellen", additional_info = "[q]Het beschadigen van een Elite op 80 % of hoger en op 20 % of onder gezondheid veroorzaakt Brann om de energie van het kristal te activeren, het verminderen van de aanval van de Elite en cast Speed % Het doden van de gerichte Elite terwijl het debuff is actief verleent de partij een 6 % stapelen Haste buff.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225068] = {name = "Optellen", additional_info = "[q]Het beschadigen van een Elite op 80 % of hoger en op 20 % of onder gezondheid veroorzaakt Brann om de energieën van het kristal te activeren, het verminderen van de aanval van de Elite en cast Speed % Het doden van de gerichte Elite terwijl het debuff is actief verleent de partij een 8 % stapelen Haste buff.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225069] = {name = "Optellen", additional_info = "[q]Terwijl de Aegis is uitgerust, alle partijleden dealen 3 % toegenomen schade en genezing. Elke 10 seconden tijdens het gevecht, jij en Brann Heelt voor 5 procent van de schade die je hebt genomen tijdens die tijd.\n\nWanneer een speler sterft, geeft de Aegis hen 1 procent vermindering van de schade en 2 procent verhoogde genezing ontvangen bij revival, maar vermindert hun schade en genezing gedeeld % stapeltijd.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225070] = {name = "Optellen", additional_info = "[q]Terwijl de Aegis is uitgerust, alle partijleden dealen 6 % verhoogde schade en genezing. Elke 10 seconden tijdens het gevecht, jij en Brann Heelt voor 10 procent van de schade die je tijdens die tijd hebt opgelopen.\n\nWanneer een speler sterft, geeft de Aegis hen 2 procent schadevermindering en 3 procent verhoogde genezing ontvangen bij revival, maar vermindert hun schade en genezing gedeeld % stapeltijd.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225072] = {name = "Optellen", additional_info = "[q]Terwijl de Aegis is uitgerust, alle partijleden dealen verhoogde schade en genezing. Elke 10 seconden tijdens het gevecht, jij en Brann Heelt van de schade die je hebt opgelopen in die tijd.\n\nWanneer een speler sterft, geeft de Aegis hen schadevermindering en verhoogde genezing ontvangen bij revival, maar vermindert hun schade en genezing gedeeld stapeltijden.\n\nJe hebt deze curio al in je collectie."}
MultiLanguageSpellData['nl'][1225073] = {name = "Optellen", additional_info = "[q]Terwijl de Aegis is uitgerust, delen alle partijleden 12 procent meer schade en genezing. Elke 10 seconden tijdens de strijd, jij en Brann Heelt voor 20 procent van de schade die je tijdens die tijd hebt opgelopen.\n\nWanneer een speler sterft, geeft de Aegis hen 4 procent schadevermindering en 5 procent verhoogde genezing ontvangen bij revival, maar vermindert hun schade en genezing gedeeld % stapeltijd.\n\nJe hebt deze curio al in je collectie."}
