MultiLanguageSpellData['nl'][1226531] = {name = "Summer Harvesthog", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"De Zomer Harvesthog ligt graag in de zon of gaat zwemmen in een helder meer. Ze zijn uitstekend in het foerageren naar voedsel, maar ze moeten erin gesjouwd worden.\"\nHandelspost"}
