MultiLanguageSpellData['nl'][1226533] = {name = "Autumn Harvesthog", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Autumn Harvesthogs blinken uit in snuffling voor voedsel in de koelere maanden. Hun scherpe reukzin maakt hen uitstekende metgezellen voor een forrest foerage, maar moeilijk te controleren in aromatische settings.\"\nHandelspost"}
