MultiLanguageSpellData['nl'][1229205] = {name = "Zand van K'aresj", additional_info = "[q]Wanneer Brann gebruik maakt van Gathering Tools, begint zand te draaien rond partijleden, waardoor Critical Strike keer en vertragen nabijgelegen vijanden.\n\nDealen van een Critical Strike creëert een Sand Devil op de locatie van het doel dat periodiek trekt vijanden naar het centrum. Kan alleen voorkomen\n\nVerzamelgereedschappen\nBrann gebruikt zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, leer en schatten te vinden."}
MultiLanguageSpellData['nl'][1229206] = {name = "Zand van K'aresj", additional_info = "[q]Wanneer Brann Gathering Tools gebruikt, begint zand te draaien rond partijleden, waardoor 8 % Critical Strike keer en vertragen nabijgelegen vijanden %.\n\nDealen van een Critical Strike creëert een Sand Devil op de locatie van het doel dat periodiek trekt vijanden naar het centrum. Kan alleen voorkomen\n\nVerzamelgereedschappen\nBrann gebruikt zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, leer en schatten te vinden."}
MultiLanguageSpellData['nl'][1229207] = {name = "Zand van K'aresj", additional_info = "[q]Wanneer Brann Gathering Tools gebruikt, begint zand te draaien rond partijleden, waardoor 10 % Critical Strike keer en vertragen nabijgelegen vijanden %.\n\nDealen van een Critical Strike creëert een Sand Devil op de locatie van het doel dat periodiek trekt vijanden naar het centrum. Kan alleen voorkomen\n\nVerzamelgereedschappen\nBrann gebruikt zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, leer en schatten te vinden."}
MultiLanguageSpellData['nl'][1229208] = {name = "Zand van K'aresj", additional_info = "[q]Wanneer Brann Gathering Tools gebruikt, begint zand te draaien rond partijleden, waardoor 12 % Critical Strike keer en vertragen nabijgelegen vijanden %.\n\nDealen van een Critical Strike creëert een Sand Devil op de locatie van het doel dat periodiek trekt vijanden naar het centrum. Kan alleen voorkomen\n\nVerzamelgereedschappen\nBrann gebruikt zijn verzameltools om spelers te helpen extra Goud, erts, kruiden, vis, leer en schatten te vinden."}
MultiLanguageSpellData['nl'][1229209] = {name = "Temporal Decelerator Crystal", additional_info = "[q]Het beschadigen van een Elite op of boven en op of onder gezondheid veroorzaakt Brann om de energie van het kristal te activeren, het verminderen van de aanval van de Elite en cast Speed Het doden van de gerichte Elite terwijl de debuff is actief verleent de partij een stapelen Haste buff."}
MultiLanguageSpellData['nl'][1229210] = {name = "Temporal Decelerator Crystal", additional_info = "[q]Het beschadigen van een Elite op 80 % of hoger en op 20 % of onder gezondheid zorgt ervoor dat Brann de energieën van het kristal activeert, waardoor de Elite's aanval wordt verminderd en Speed % wordt gegoten Het doden van de doel Elite terwijl de debuff actief is verleent de partij een 4 % stapelen Haste buff."}
MultiLanguageSpellData['nl'][1229211] = {name = "Temporal Decelerator Crystal", additional_info = "[q]Het beschadigen van een Elite op 80 % of hoger en op 20 % of onder gezondheid veroorzaakt Brann om de energie van het kristal te activeren, het verminderen van de aanval van de Elite en cast Speed % Het doden van de gerichte Elite terwijl het debuff is actief verleent de partij een 6 % stapelen Haste buff."}
MultiLanguageSpellData['nl'][1229212] = {name = "Temporal Decelerator Crystal", additional_info = "[q]Het beschadigen van een Elite op 80 % of hoger en op 20 % of onder gezondheid veroorzaakt Brann om de energieën van het kristal te activeren, het verminderen van de aanval van de Elite en cast Speed % Het doden van de gerichte Elite terwijl het debuff is actief verleent de partij een 8 % stapelen Haste buff."}
MultiLanguageSpellData['nl'][1229213] = {name = "Batterij Aegis", additional_info = "[q]Terwijl de Aegis is uitgerust, alle partijleden dealen 3 % toegenomen schade en genezing. Elke 10 seconden tijdens het gevecht, jij en Brann Heelt voor 5 procent van de schade die je hebt genomen tijdens die tijd.\n\nWanneer een speler sterft, geeft de Aegis hen 1 procent vermindering van de schade en 2 procent verhoogde genezing ontvangen bij revival, maar vermindert hun schade en genezing gedeeld % stapeltijd."}
MultiLanguageSpellData['nl'][1229214] = {name = "Batterij Aegis", additional_info = "[q]Terwijl de Aegis is uitgerust, alle partijleden dealen 6 % verhoogde schade en genezing. Elke 10 seconden tijdens het gevecht, jij en Brann Heelt voor 10 procent van de schade die je tijdens die tijd hebt opgelopen.\n\nWanneer een speler sterft, geeft de Aegis hen 2 procent schadevermindering en 3 procent verhoogde genezing ontvangen bij revival, maar vermindert hun schade en genezing gedeeld % stapeltijd."}
MultiLanguageSpellData['nl'][1229215] = {name = "Batterij Aegis", additional_info = "[q]Terwijl de Aegis is uitgerust, alle partijleden dealen verhoogde schade en genezing. Elke 10 seconden tijdens het gevecht, jij en Brann Heelt van de schade die je hebt opgelopen in die tijd.\n\nWanneer een speler sterft, geeft de Aegis hen schadevermindering en verhoogde genezing ontvangen bij revival, maar vermindert hun schade en genezing gedeeld stapeltijden."}
MultiLanguageSpellData['nl'][1229216] = {name = "Batterij Aegis", additional_info = "[q]Terwijl de Aegis is uitgerust, delen alle partijleden 12 procent meer schade en genezing. Elke 10 seconden tijdens de strijd, jij en Brann Heelt voor 20 procent van de schade die je tijdens die tijd hebt opgelopen.\n\nWanneer een speler sterft, geeft de Aegis hen 4 procent schadevermindering en 5 procent verhoogde genezing ontvangen bij revival, maar vermindert hun schade en genezing gedeeld % stapeltijd."}
