MultiLanguageSpellData['nl'][1233375] = {name = "Kleine Rune van Oneindige Sterren", additional_info = "[q]Apply Lesser Rune of Infinite Stars to a helm.\n\nUw spreuken en vermogens hebben een kans om een nabije vijand te slaan met een Oneindige Ster, omgaan (1 * 211298) Arcaneschade en het verhogen van hun schade genomen uit uw Oneindige Sterren door (1 * 73954), stapelen tijden voor het resetten.\n\nKan niet worden toegepast op items onder niveau 350. Dit effect is vluchtig en zal alleen werken tijdens The War Within Season 2."}
