MultiLanguageSpellData['nl'][1233539] = {name = "Snijden", additional_info = "[q]Op het bereiken van 100 Energie Dimensius verhoogt zijn dichtheid, het creëren van een krachtige innerlijke kracht die Schaduwschade elke 1 en trekt in spelers, Voidstars, Black Holes, en de Accretion Disk.\n\nNa 5 sec elke speler buiten een Voidstar's Gravity Well wordt onmiddellijk getrokken in Dimensius en verzonden naar Oblivion."}
MultiLanguageSpellData['nl'][1233542] = {name = "De botvriezer", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Bitter rivaal van The Bone Melter, deze kruiper werd verdreven uit hun hol in de buurt van Manaforge Omega na een verpletterende nederlaag. Het probeert nu te leren van degene die zijn grootste vijand onttroond heeft.\"\nManaforge Vandalen\nHerinnering:\n14\nLocatie:\nSchaduwpunt"}
