MultiLanguageSpellData['nl'][1233896] = {name = "Batterij Aegis", additional_info = "[q]Terwijl de Aegis is uitgerust, alle partijleden dealen verhoogde schade en genezing. Elke 10 seconden tijdens het gevecht, jij en Brann Heelt van de schade die je hebt opgelopen in die tijd.\n\nWanneer een speler sterft, geeft de Aegis hen schadevermindering en verhoogde genezing ontvangen bij revival, maar vermindert hun schade en genezing gedeeld stapeltijden."}
MultiLanguageSpellData['nl'][1233897] = {name = "Temporal Decelerator Crystal", additional_info = "[q]Het beschadigen van een Elite op of boven en op of onder gezondheid veroorzaakt Brann om de energie van het kristal te activeren, het verminderen van de aanval van de Elite en cast Speed Het doden van de gerichte Elite terwijl de debuff is actief verleent de partij een stapelen Haste buff."}
