MultiLanguageSpellData['nl'][1233938] = {name = "Quizzisch apparaat", additional_info = "[q]Brann heeft de kans om spelers een bonus te geven voor gezondheid, schade of genezing op basis van zijn geselecteerde Combat Role.\n\nSpelers hebben een kans om Brann een bonus te geven aan gezondheid, schade, of genezing op basis van hun geselecteerde rol.\n(20s cooldown)"}
MultiLanguageSpellData['nl'][1233940] = {name = "Etherische Energie Converter", additional_info = "[q]Wanneer een partijlid daalt onder gezondheid, een Ethereal Energie Converter materialiseert, dealen matige schade aan nabijgelegen vijanden en treiteren hen Zodra de treunt verloopt, de Converter releases een Etherwave genezing nabij bondgenoten van hun gezondheid. Kan worden geactiveerd Het doden van vijanden vermindert de cooldown van dit effect sec."}
