MultiLanguageSpellData['nl'][1234351] = {name = "Arcane-inspiratie", additional_info = "[q]Artifact vermogen\n\nGooi een schijf van arcane Energie die naar buiten boog voordat hij naar je terugkeert.\n\nNaran's Everdisc brengt [( Attack/Spell Power)] Arcaneschade aan vijanden op zijn pad.\n\nOnderbreek het terugkerende projectiel om een absorberen Schild te krijgen en gooi het opnieuw extra tijden."}
