MultiLanguageSpellData['nl'][1234362] = {name = "Aanraking van Malice", additional_info = "[q]Grants 5 extra rangen van Touch of Malice.\n\nAanraking van Malice\nDe schadelijke spreuken en vermogens van uw volgelingen.. passen regelmatig Fel Touched toe op vijanden. De helse dreadlord die door Twisted Crusade werd opgeroepen, slaat altijd kritiek op Fel Touched vijanden.\n\nFel Touched\nElke 4 seconden barsten de doelwitten.. en beschadigen de vijanden van de schade.\n\nSchade verminderd boven 5 doelen."}
