MultiLanguageSpellData['nl'][1235879] = {name = "Gestoord", additional_info = "[q]Het nemen van schade infurieert u, waardoor u schade te absorberen en deal Schaduwschade per infuriatie splitsen tussen nabijgelegen vijanden. De schade steeg per extra vijand,%.\n\nU kunt verder woedend, stapeltijd, maar kalmeer snel bij het verlaten van het gevecht.\n\nAlleen geldig voor tankspecialisaties."}
