MultiLanguageSpellData['nl'][1235934] = {name = "Lichthamer", additional_info = "[q]Hammer neer uw vijand met de kracht van het Licht, omgaan Heilige schade en Heilige schade nabijgelegen vijanden.\n\nBovendien, roept Empyrean Hammers uit de lucht te slaan 3 nabijgelegen vijanden voor Heilige schade elk."}
MultiLanguageSpellData['nl'][1235946] = {name = "Merk van Ceaseless Ire", additional_info = "[q]Het nemen van schade infurieert u, waardoor u schade te absorberen en deal Schaduwschade per infuriatie splitsen tussen nabijgelegen vijanden. De schade steeg per extra vijand,%.\n\nU kunt verder woedend, stapeltijd, maar kalmeer snel bij het verlaten van het gevecht.\n\nAlleen geldig voor tankspecialisaties."}
MultiLanguageSpellData['nl'][1235959] = {name = "Mage Spellslinger 11.2 Klasse Set 2pc", additional_info = "[q]Arcane\nArcane Blast schade verhoogd en Arcane Blast verleent 1 stapel Arcane Harmony. Directe Splinter schade heeft een kans om een stapel Arcane Harmony.\n\nVuur, Frost.\nIce Lance en Icicle schade verhoogd en Ice Lance heeft een kans om te genereren stapel van Cold Front. Directe splinterschade heeft de kans om een stapel Cold Front toe te kennen."}
MultiLanguageSpellData['nl'][1235962] = {name = "Mage Sunfury 11.2 Klasse Set 2pc", additional_info = "[q]Arcane, Fire, Frost\nSpellfire Sphere spelling schade bonus verhoogd. Mana Cascade verleent nu een extra Haste per stack."}
MultiLanguageSpellData['nl'][1235963] = {name = "Mage Frostfire 11.2 Klasse Set 2pc", additional_info = "[q]Vuur\nComet Storm en Frostfire Burst schade toegenomen. Frostfire Bolt schade toegenomen. Comet Storm, Frostfire Burst en Frostfire Bolt passen Ignite nu toe op effectiviteit.\n\nArcane, Frost\nMeteor en Frostfire Burst schade toegenomen. Frostfire Bolt schade toegenomen. Meteor, Frostfire Burst, en Frostfire Bolt gelden nu Ignite, het omgaan met een extra schade"}
MultiLanguageSpellData['nl'][1235964] = {name = "Mage Spellslinger 11.2 Klasse Set 4pc", additional_info = "[q]Arcane\nSplinterschade toegenomen. Arcane Orb heeft een kans om een stapel Arcane Harmony, tijden. Bij het bereiken van 20 stapels Arcane Harmony, krijgen Intuïtie op effectiviteit.\n\nVuur\nSplinterschade toegenomen. Arcane Orb heeft een kans om een stapel Arcane Harmony, tijden. Als Cold Front een bevroren bol oproept, verhoog je spreukschade.\n\nFrost\nAls Frozen Orb schade behandelt aan één of meerdere vijanden, heeft het een kans om een stapel Cold Front toe te kennen. Als Cold Front een bevroren bol oproept, verhoog je spreukschade."}
MultiLanguageSpellData['nl'][1235965] = {name = "Mage Sunfury 11.2 Klasse Set 4pc", additional_info = "Frost, Frost.\nUitzonderlijke spreuken van uw Phoenix voegt een extra 0.3 sec toe aan de duur van uw volgende Hyperthermie. Wanneer uw Phoenix verloopt, geeft het u nog meer kracht, waardoor u minder tijd krijgt en meer spreukschade krijgt.\n\nArcane\nUitzonderlijke spreuken van uw Phoenix voegt een extra 0.5 sec toe aan de duur van uw volgende Arcane Ziel. Wanneer uw Phoenix verloopt, geeft het u nog meer kracht, waardoor u minder tijd krijgt en meer spreukschade krijgt."}
MultiLanguageSpellData['nl'][1235966] = {name = "Mage Frostfire 11.2 Klasse Set 4pc", additional_info = "[q]Arcane, Frost\nCasting Glacial Spike heeft ook de kans om een Pyroblast te casten, dealen Vuurschade. Daarnaast profiteert Pyroblast nu van Ignite.\n\nVuur\nCasting Pyroblast heeft ook de kans om een Glacial Spike dealen Vorstschade. Glacial Spikes cast deze kant niet Vastworteling. Daarnaast profiteert Glacial Spike nu van Ignite."}
