MultiLanguageSpellData['nl'][1236254] = {name = "Death Knight Deathbringer 11.2 Klasse Set 4pc", additional_info = "[q]Blood, Frost, Unholy\nVernietig deals toegenomen schade, en Reaper's Mark kan extra tijden stapelen. Bij exploderen, Reaper's Mark verhoogt uw Critical Strike kans\n(1s cooldown)"}
