MultiLanguageSpellData['nl'][1236259] = {name = "Death Knight San'layn 11.2 Klasseset 2pc", additional_info = "PH00Unholy\nInfliction of Sorrow verlengt de duur van uw ziekte met een extra 3,0 sec op uw hoofddoel, en Essentie van de Blood Queen verhoogt bovendien uw Mastery per stack.\n\nBloed, Frost.\nInfliction of Sorrow verlengt de duur van uw ziekte met een extra 4.0 sec op uw hoofddoel, en Essentie van de Blood Queen verhoogt bovendien uw Mastery per stack."}
MultiLanguageSpellData['nl'][1236260] = {name = "Death Knight San'layn 11.2 Klasse Set 4pc", additional_info = "PH00Unholy\nInfliction of Sorrow behandelt toegenomen schade, en Vampiric Strike verhoogt de schade van uw ghoul Meerdere toepassingen kunnen overlappen.\n\nBloed, Frost.\nInfliction of Sorrow behandelt verhoogde schade, en Vampiric Strike verhoogt de schade van uw Dancing Rune Wapens Meerdere toepassingen kunnen overlappen."}
MultiLanguageSpellData['nl'][1236262] = {name = "Shaohao's salie slang", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"De lessen die Shaohao leerde in leven en dood en de passie die hij voor zijn huis had, zijn samengesmolten in deze etherische slang, een weerspiegeling van de wijsheid van de keizer.\"\nBevordering:\nMist van Pandaria Classic"}
