MultiLanguageSpellData['nl'][1236272] = {name = "Kritieke ketting", additional_info = "[q]Uw spreuken en vaardigheden hebben een kans om te activeren Kritische Overbelasting, het verhogen van uw Critical Strike\n(20s cooldown)"}
MultiLanguageSpellData['nl'][1236273] = {name = "Spark Burst", additional_info = "[q]Uw spreuken en vaardigheden hebben een kans om een Spark Burst u 139 Haste te activeren"}
MultiLanguageSpellData['nl'][1236275] = {name = "Statische lading", additional_info = "[q]Uw spreuken en vaardigheden hebben de kans om u Static Charge, het verhogen van uw Versatility door (14 * 20) Elk van uw volgende spreuken en vaardigheden verminderen de Versatility bonus.\n(29s cooldown)"}
MultiLanguageSpellData['nl'][1236276] = {name = "Elektrische stroom", additional_info = "[q]Je krijgt elektrische stroom bij het invoeren van gevecht, het verhogen van uw Mastery tot een maximum van (12 * 8 ) na 24 sec dan fietsen Back naar beneden en herhalen."}
MultiLanguageSpellData['nl'][1236277] = {name = "Opgeladen touch", additional_info = "[q]Uw Heelt hebben een kans om Spark springen naar de laagste gezondheid doel binnen bereik, hen genezen voor 1766."}
