MultiLanguageSpellData['nl'][1236330] = {name = "Druïde Druïde van de Klauw 11.2 Klasse Set 4pc", additional_info = "[q]Feral\nRavage heeft de kans om je doel weer te vernietigen 4 seconden later bij de eerste kracht.\n\nBalance, Guardian, Restauratie\nRavage heeft de kans om je weer 4 seconden later je doel te laten verwoesten."}
MultiLanguageSpellData['nl'][1236331] = {name = "Druïde Druïde van de Klauw 11.2 Klasse Set 2pc", additional_info = "[q]Ravage verhoogt uw Haste, de kans om kritisch toe te slaan, en de schade die uw Bloedt deal"}
MultiLanguageSpellData['nl'][1236332] = {name = "Druid Elune's gekozen 11.2 Klasse Set 2pc", additional_info = "[q]Balance\nDe schade aan het sterrenvuur is toegenomen. Het winnen van Astrale Kracht met Starfire heeft een kans om een Starsurge te lanceren op een slachtoffer bij effectiviteit.\n\nFeral, Guardian, Restauratie\nDe schade is toegenomen. Thrash heeft een kans om een Starsurge te lanceren op een slachtoffer bij effectiviteit."}
MultiLanguageSpellData['nl'][1236333] = {name = "Druid Elune's gekozen 11.2 klasse Set 4pc", additional_info = "[q]Balance\nOp impact, Starsurges gelanceerd door Starfire splitsen naar extra doelen op effectiviteit en verlenen een stapel van Gathering Moonlight. Gieten Furie van Elune of Volle Maan verbruikt Verzamelen Maanlicht om uw schade per stack te verhogen\n\nFeral, Guardian, Restauratie\nOp impact, Starsurges gelanceerd door Thrash splitsen naar extra doelen op effectiviteit en verlenen een stapel van Gathering Moonlight. Gieten Maanstraal verbruikt Verzamelen Maanlicht om uw schade per stack te verhogen"}
MultiLanguageSpellData['nl'][1236334] = {name = "Druïde Keeper van de Grove 11.2 Klasse Set 2pc", additional_info = "[q]Balance, Feral, Guardian\nCasting Celestial Alignment roept de hulp van een dryad die Starsurge werpt op effectiviteit en Starfall op effectiviteit.\n\nHerstel\nCasting Incarnation: Boom van het Leven of Convoce de Geesten roept de hulp van een dryad die Tranquility werpt op effectiviteit en onmiddellijk hergroeit uw laagste gezondheid bondgenoot in effectiviteit."}
MultiLanguageSpellData['nl'][1236336] = {name = "Druïde Keeper van de Grove 11.2 Klasse Set 4pc", additional_info = "[q]Balance, Feral, Guardian\nWanneer uw Dryad vervaagt, uw volgende 2 Starsurges schade voor een extra bedrag gelijk aan uw schade gedaan terwijl het actief was en splash van hun schade op nabijgelegen vijanden, gereduceerd tot meer dan 5 doelen.\n\nHerstel\nWanneer uw Dryad vervaagt, uw volgende 2 Swiftmends Heelt voor een extra bedrag gelijk aan uw genezing gedaan terwijl het actief was en splash van hun genezing op nabijgelegen bondgenoten, gereduceerd tot meer dan 5 doelen."}
MultiLanguageSpellData['nl'][1236337] = {name = "Druid Wildstalker 11.2 Klasse Set 2pc", additional_info = "[q]Feral\nDe snelheid waarmee Bloodseeker Vines groeit is verhoogd. Tiger's Furie zorgt ervoor dat Bloodseeker Vines groeien op geldige nabijgelegen vijanden.\n\nBalance, Guardian, Restauratie\nDe snelheid waarmee Symbiotische Blooms groeien wordt verhoogd. Afgietsel Hergroei met Clearcasting zorgt ervoor dat Symbiotic Blooms groeien op geldige nabijgelegen bondgenoten."}
MultiLanguageSpellData['nl'][1236338] = {name = "Druid Wildstalker 11.2 Klasse Set 4pc", additional_info = "[q]Feral\nBloedzoeker Vines hebben een kans om Bursting Growth op effectiviteit te activeren. Elke stapel van Bloodseeker Vines op een vijand verhoogt Bursting Groeischade genomen.\n\nBalance, Guardian, Restauratie\nSymbiotische Blooms hebben een kans om te activeren Bursting Groei op effectiviteit. Elke stapel van Symbiotic Blooms op een bondgenoot verhoogt Bursting Groei genezing genomen."}
MultiLanguageSpellData['nl'][1236342] = {name = "Voorbereiden van staking", additional_info = "[q]Feral\nRavage heeft de kans om je doel weer te vernietigen 4 seconden later bij de eerste kracht.\n\nBalance, Guardian, Restauratie\nRavage heeft de kans om je weer 4 seconden later je doel te laten verwoesten."}
MultiLanguageSpellData['nl'][1236343] = {name = "Abyssale detonatie", additional_info = nil}
MultiLanguageSpellData['nl'][1236348] = {name = "Opgeladen slash", additional_info = "[q]Zo'phex laadt zijn zwaarden op en ontketent een enorme slag, waardoor Fysieke schade aan alle vijanden voor hem wordt toegebracht."}
MultiLanguageSpellData['nl'][1236350] = {name = "Void Power Shard vrijgegeven beelden - Cosmetic", additional_info = nil}
MultiLanguageSpellData['nl'][1236354] = {name = "Soul Siphon", additional_info = "[q]Caster Vertraagt hun doel en afvoert 622547 gezondheid, genezing van de caster voor twee keer de hoeveelheid gedraineerd."}
MultiLanguageSpellData['nl'][1236355] = {name = "Death Knight Rider van de Apocalyps 11.2 Klasse Set 2pc", additional_info = "[q]Blood, Unholy\nApocalyps roept nu Whitemane Whitemane's Undeath deals verhoogde schade en infecteert 1 extra doelwit wanneer het zich verspreidt, en haar Death Coil deals toegenomen schade.\n\nFrost\nPillar of Frost roept nu Trollbane Trollbane's Icy Furie deals toegenomen schade en zijn Obliterate deals toegenomen schade."}
MultiLanguageSpellData['nl'][1236356] = {name = "Death Knight Rider van de Apocalyps 11.2 Klasse Set 4pc", additional_info = "[q]Blood, Unholy\nCasting Death Coil of Epidemic beveelt Whitemane om haar Death Coil of Epidemic samen met jou te werpen op effectiviteit. Jouw Death Coil dealt verhoogde schade aan doelwitten getroffen door Whitemane's Undeath.\n\nFrost\nHet Casting Obliterate of Frostscy.. beveelt Trollbane om zijn Obliterate of Frostscythe naast je te werpen. Jouw obliterate dealt verhoogde schade aan doelwitten beïnvloed door Trollbane's Icy Furie."}
MultiLanguageSpellData['nl'][1236358] = {name = "Demon Hunter Aldrachi Reaver 11.2 Klasse Set 2pc", additional_info = "[q]Reaver's Glaive schade wordt verhoogd en andere fysieke-only schade wordt verhoogd."}
MultiLanguageSpellData['nl'][1236360] = {name = "Demon Hunter Aldrachi Reaver 11.2 Klasse Set 4pc", additional_info = "[q]Havoc\nFurie van de Aldrachi geeft Blade Dance nog meer kracht na Chaos Strike, waardoor het aantal slashes toeneemt tot 12.\n\nReaver's Mark stapelt nu tijden en versterkt Chaos Strike bij cast na Blade Dance, waarbij een extra stapel van normale duur wordt toegepast.\n\nWraak\nFurie van de Aldrachi verder versterkt Ziel Cleave wanneer gegoten na Shear, toenemende slashes tot 12.\n\nReaver's Mark stapelt nu tijden en versterkt Shear wanneer gegoten na Soul Cleave, het toepassen van een extra stack van normale duur."}
MultiLanguageSpellData['nl'][1236361] = {name = "Demon Hunter Fel-Scarred 11.2 Klasseset 2pc", additional_info = "[q]Havoc\nImmolation Aura behandelt verhoogde schade en verhoogt Chaos Strike schade terwijl actief.\n\nWraak\nImmolation Aura behandelt verhoogde schade en verhoogt de Soul Cleave schade terwijl actief."}
MultiLanguageSpellData['nl'][1236362] = {name = "Demon Hunter Fel-Scarred 11.2 Klasse Set 4pc", additional_info = "[q]Havoc\nHet binnengaan van demonenvorm leidt onmiddellijk tot een Demonchirurgie en verbrijzelt een demonenzielfragment dat verhoogde schade verleent.\n\nWraak\nHet binnengaan van demonenvorm leidt onmiddellijk tot een Demonchirurgie en verbrijzelt een demonenzielfragment dat verhoogde schade verleent."}
MultiLanguageSpellData['nl'][1236364] = {name = "Evoker Flameshaper 11.2 Klasse Set 2pc", additional_info = "[q]Vernietiging\nEngulf stookt uw Innerlijke Vlam, het verhogen van uw schade en genezing na verloop van tijd en het verhogen van uw kans om Essentie Burst Stacks tijden te krijgen. Meerdere aanvragen kunnen elkaar overlappen.\n\nBehoud, Augmentatie\nEngulf stookt uw Innerlijke Vlam, het verhogen van uw schade en genezing na verloop van tijd en het verhogen van uw kans om Essentie Burst Stacks tijden te krijgen. Meerdere aanvragen kunnen elkaar overlappen."}
MultiLanguageSpellData['nl'][1236365] = {name = "Evoker Flameshaper 11.2 Klasse Set 4pc", additional_info = "[q]Vernietiging\nHet consumeren van Essentie Burst tijdens Inner Flame vuurt een Essentie Bom op uw doel, schadelijke nabijgelegen vijanden voor Arcane, gereduceerd tot meer dan 5 doelen.\n\nBehoud, Augmentatie\nHet consumeren van Essentie Burst tijdens Inner Flame vuurt een Essentie Bom op uw doel, helende nabijgelegen bondgenoten voor, gereduceerd tot meer dan 5 doelen."}
MultiLanguageSpellData['nl'][1236366] = {name = "Evoker Scalecommander 11.2 Klasseset 2pc", additional_info = "[q]augmentatie\nTijdens het vliegen tijdens Deep Breath en 20 seconden daarna, voer je het bevel over een eskader van 2 Dracthyr die je doelwitten zal aanvallen met Disintegrate en Pyre.\n\nVernietiging, conservering\nTijdens het vliegen tijdens Deep Breath en 10 seconden daarna, voer je het bevel over een eskader van 2 Dracthyr die je doelwitten zal aanvallen met Disintegrate en Pyre."}
MultiLanguageSpellData['nl'][1236367] = {name = "Evoker Scalecommander 11.2 Klasse Set 4pc", additional_info = "[q]Vernietiging\nTerwijl je eskader actief is, slaat je Mass Disintegrate extra doelwitten aan. Bovendien helpt je eskader je nog 5 seconden.\n\nAugmentatie\nTerwijl je eskader actief is, slaat je massale uitbarsting extra doelen. Bovendien helpt je eskader je nog 10 seconden.\n\nBehoud\nTerwijl je eskader actief is, slaat je massale uitbarsting extra doelen. Bovendien helpt je eskader je nog 5 seconden."}
MultiLanguageSpellData['nl'][1236368] = {name = "Evoker Chronowarden 11.2 Klasseset 2pc", additional_info = "[q]Tip de schaalverdeling cooldown is verminderd sec."}
MultiLanguageSpellData['nl'][1236369] = {name = "Evoker Chronowarden 11.2 Klasse Set 4pc", additional_info = "[q]Temporal Burst zorgt ervoor dat Chrono Flames 2 extra doelen raken en herhalen extra schade of genezing, tot een maximum van, en verhoogt Essentie vermogen schade en genezing."}
MultiLanguageSpellData['nl'][1236370] = {name = "Hunter Dark Ranger 11.2 Klasse Set 2pc", additional_info = "[q]Beast Mastery\nBlack Arrow pijlschade verhoogd en Bleak Powder schade verhoogd. De cooldown van Call of the Wild is verminderd sec.\n\nMarkmanschap, Survival\nBlack Arrow pijlschade verhoogd en Bleak Powder schade verhoogd. De cooldown van Trueshot is verminderd sec."}
MultiLanguageSpellData['nl'][1236371] = {name = "Hunter Dark Ranger 11.2 Klasse Set 4pc", additional_info = "[q]Beast Mastery, Marksmanship, Survival\nDe schade aan de Zwarte Pijl van Withering Fire is toegenomen. Consuming Deathblow heeft de kans om alle Black Arrow barrages tijdens uw volgende Withering Fire te vuren 1 extra Black Arrow."}
MultiLanguageSpellData['nl'][1236372] = {name = "Hunter Pack Leader 11.2 Klasse Set 2pc", additional_info = "[q]Marksmanship, Survival\nDe schade aan de dieren nam toe en de schade aan het beest nam toe. Het oproepen van een Beest subsidies Haste, Mastery, of Critical Strike kans op basis van het Beest opgeroepen\n\nBeest Mastery\nDe schade aan de dieren nam toe en de schade aan het beest nam toe. Het oproepen van een Beest subsidies Haste, Mastery, of Critical Strike kans op basis van het Beest opgeroepen"}
MultiLanguageSpellData['nl'][1236373] = {name = "Hunter Pack Leader 11.2 Klasse Set 4pc", additional_info = "[q]Summoning een Beest terwijl onder de effecten van Lead van het Front leidt de nabijgelegen wilde dieren in een Stampede, opladen van uw doel en dealen Fysieke schade aan vijanden"}
MultiLanguageSpellData['nl'][1236374] = {name = "Hunter Sentinel 11.2 Klasse Set 2pc", additional_info = "[q]Marksmanschap\nSnelle Vuurschade verhoogd. Wanneer Lunar Storm vervaagt, krijgen de Boon van Elune, waardoor uw volgende 2 Aimed Shots om Arcaneschade en hun schade verhoogd.\n\nBeast Mastery, Survival\nDe schade aan de bom is toegenomen. Wanneer Lunar Storm vervaagt, krijgen de Boon van Elune, waardoor uw volgende 2 Wildfire Bombs om Arcaneschade en hun eerste schade verhoogd."}
MultiLanguageSpellData['nl'][1236375] = {name = "Hunter Sentinel 11.2 Klasse Set 4pc", additional_info = "[q]Marksmanschap\nSentinel's schade is toegenomen. De Boon van Elune is nu actief voor de duur van Lunar Storm bij effectiviteit.\n\nBeast Mastery, Survival\nSentinel's schade is toegenomen. De Boon van Elune is nu actief voor de duur van Lunar Storm bij effectiviteit."}
MultiLanguageSpellData['nl'][1236376] = {name = "Soul Ravel", additional_info = nil}
MultiLanguageSpellData['nl'][1236377] = {name = "Monk Master of Harmony 11.2 Klasse Set 2pc", additional_info = "[q]Brewmaster\nHet verkrijgen van vitaliteit heeft een toenemende kans om uw volgende Tiger Palm om een Harmonic Surge los te laten, dealen Natuurschade split tussen uw doel en andere nabijgelegen vijanden, en genezing van gewonde bondgenoten.\n\nWindwalker, Mistweaver\nHet verkrijgen van vitaliteit heeft een toenemende kans om uw volgende Tiger Palm om een Harmonic Surge los te laten, dealen Natuurschade split tussen uw doel en andere nabijgelegen vijanden, en genezing van gewonde bondgenoten."}
MultiLanguageSpellData['nl'][1236378] = {name = "Monkmeester van Harmonie 11.2 Klasse Set 4pc", additional_info = "[q]Windwalker, Mistweaver\nCasting Thunder Focus Thee garandeert dat uw volgende 2 afgietsels van Tiger Palm een Harmonic Surge zal veroorzaken.\n\nBrewmaster\nCasting garandeert dat je volgende 2 afgietsels van Tiger Palm een Harmonic Surge zal veroorzaken."}
MultiLanguageSpellData['nl'][1236379] = {name = "Monk Shado-Pan 11.2 Klasseset 2pc", additional_info = "[q]Brewmaster\nFlury Strikes dealen meer schade en het activeren van Wapens van Orde onmiddellijk verleent 10 stapels van Flury Strikes die trigger op uw volgende aanval op effectiviteit.\n\nWindwalker, Mistweaver\nFlury Strikes dealen meer schade en het activeren van Storm, Aarde, en Vuur onmiddellijk verleent 10 stapels van Flury Strikes die trigger op uw volgende aanval op effectiviteit."}
MultiLanguageSpellData['nl'][1236380] = {name = "Monk Shado-Pan 11.2 Klasse Set 4pc", additional_info = "[q]Brewmaster\nDe opladingsgeneratie van de golfslag wordt verhoogd en Flury Strikes activeert elke 150 Energie besteed tijdens Wapens of Order.\n\nWindwalker\nVloeistof lading generatie wordt verhoogd en Flury Strikes triggers elke 120 Energie besteed tijdens Storm, Aarde en Vuur.\n\nMistweaver\nDe opladingsgeneratie van de golfslag wordt verhoogd en Flury Strikes activeert elke 150 Energie besteed tijdens Wapens of Order."}
MultiLanguageSpellData['nl'][1236381] = {name = "Monk Conduit van de Hemelen 11.2 Klasse Set 2pc", additional_info = "[q]Windwalker\nHart van de Jade Serpent extra triggers bij effectiviteit nadat u Slicing Winds.\n\nBrouwmeester, Mistweaver\nHart van de Jade Serpent extra triggers bij effectiviteit nadat u cast Thunder Focus Tea.\n\n(1s cooldown)"}
MultiLanguageSpellData['nl'][1236382] = {name = "Monk Conduit van de Hemelen 11.2 Klasse Set 4pc", additional_info = "[q]Hart van de Jade Serpent verhoogt uw Haste terwijl u actief bent en daarna."}
MultiLanguageSpellData['nl'][1236383] = {name = "Paladin Herald van de Zon 11.2 Klasse Set 2pc", additional_info = "[q]Retributie\nDe genezing en schade van Dawnlight wordt verhoogd en je krijgt Solar Wrath na Wrath Wrath vervaagt waardoor Sun's Avatar effect blijft hangen voor een extra [10][10] sec.\n\nBescherming\nDe genezing en schade van Dawnlight wordt verhoogd en je krijgt Solar Wrath na Wrath Wrath vervaagt waardoor Sun's Avatar effect blijft hangen voor een extra [10][10] sec.\n\nHoly (Avenging Wrath)\nDawnlight's genezing en schade wordt verhoogd en je krijgt Solar Wrath na Wrath Wrath vervaagt waardoor Sun's Avatar effect blijft hangen voor een extra 10[10][10] sec."}
MultiLanguageSpellData['nl'][1236384] = {name = "Paladin Herald van de Zon 11.2 Klasse Set 4pc", additional_info = "[q]Retributie\nSolar Wrath verhoogt de effectiviteit van uw Heilige Kracht uitgaven en verleent u [2][2] Dawnlight.\n\nBescherming\nSolar Wrath verhoogt de effectiviteit van uw Heilige Kracht uitgaven en verleent u [2][2] Dawnlight.\n\nHoly (Avenging Wrath)\nSolar Wrath verhoogt de effectiviteit van uw Heilige Kracht uitgaven en verleent u 2[2][2] Dawnlight."}
MultiLanguageSpellData['nl'][1236385] = {name = "Soul Strafe", additional_info = nil}
MultiLanguageSpellData['nl'][1236389] = {name = "Paladin Lightsmith 11.2 Klasse Set 2pc", additional_info = "[q]Protection\nHammer en Anvil's schade wordt verhoogd en het kan ook worden geactiveerd door bij effectiviteit.\n\nVergelding\nHammer en Anvil's genezing wordt verhoogd en het kan ook worden geactiveerd door Crusader Strike op effectiviteit.\n\nHeilige\nHammer en Anvil's genezing wordt verhoogd en het kan ook worden geactiveerd door Crusader Strike op effectiviteit."}
MultiLanguageSpellData['nl'][1236390] = {name = "Paladin Lightsmith 11.2 Klasse Set 4pc", additional_info = "[q]Hammer en Anvil verleent ook een stapel meesterwerk, waardoor uw volgende Heilig Bewapening te werpen een kleinere versie van zichzelf op een nabijgelegen bondgenoot voor elke stack."}
MultiLanguageSpellData['nl'][1236391] = {name = "Paladin Templar 11.2 Klasse Set 2pc", additional_info = "[q]Uw Empyrean Hammer deals verhoogd Critical Strike schade en de kritische stakingen hebben de kans om een extra stapel van Light's Deliverance."}
MultiLanguageSpellData['nl'][1236392] = {name = "Paladin Tempeliers 11,2 Klasse Set 4pc", additional_info = "[q]Holy, Bescherming\nHammer of Light dealt verhoogde schade aan zijn primaire doel, slaat 3 extra secundaire doelen, en kan nu worden gegoten 1 meer tijd na Eye of Tyr.\n\nVergelding\nHammer of Light deals toegenomen schade aan zijn primaire doel, slaat 3 extra secundaire doelen, en kan nu worden gegoten 1 meer tijd na Wake of Ashes."}
MultiLanguageSpellData['nl'][1236394] = {name = "Priester Oracle 11.2 Klasse Set 2pc", additional_info = "[q]Holy, Shadow\nCasting Prayer of Mending Heelt uw doel.\n\nVakgebied\nDe eerste bout van elke Penance cast schade of Heelt voor meer."}
MultiLanguageSpellData['nl'][1236395] = {name = "Priester Oracle 11.2 Klasse Set 4pc", additional_info = "[q]Casting Premonition of vroomheid of Premonition of Solace verleent 2 stapels Premonition of Insight op effectiviteit. Het consumeren van een stapel van Voorgevoel van Insight verhoogt uw Haste Meerdere toepassingen kunnen overlappen."}
MultiLanguageSpellData['nl'][1236396] = {name = "Priester Voidweaver 11.2 Klasseset 2pc", additional_info = "[q]Discipline\nVoid Blast en Penance schade wordt verhoogd en Void Blast's gegoten tijd wordt verminderd.\n\nHeilige\nVoid Blast schade wordt verhoogd en Void Blast's gegoten tijd is verminderd.\n\nSchaduw\nVoid Blast schade wordt verhoogd en Void Blast's gegoten tijd is verminderd. Void Blast's cooldown is verminderd."}
MultiLanguageSpellData['nl'][1236397] = {name = "Priester Voidweaver 11.2 Klasse Set 4pc", additional_info = "[q]Discipline\nVoid Blast zorgt er nu ook voor dat Entropic Rift groeit, Collapsing Leid verhoogt Entropic Rift's schade door een extra, en de schade van uw volgende Mind Blast wordt verhoogd met% op basis van de grootte van Entropic Rift wanneer het instort.\n\nHeilige\nVoid Blast zorgt er nu ook voor dat Entropic Rift groeit, Collapsing Void verhoogt Entropic Rift's schade door een extra, en de schade van uw volgende Void Torrent wordt verhoogd met% op basis van de grootte van Entropic Rift wanneer het instort.\n\nSchaduw\nVoid Blast zorgt er nu ook voor dat Entropic Rift groeit, Collapsing Void verhoogt Entropic Rift's schade door een extra, en de schade van uw volgende Void Torrent wordt verhoogd met% op basis van de grootte van Entropic Rift wanneer het instort."}
MultiLanguageSpellData['nl'][1236398] = {name = "Priester Archon 11.2 Klasse Set 2pc", additional_info = "[q]Shadow\nHalos genereren een extra 10 Waanzin en Resonant Energie verhoogt bovendien de schade van uw Devouring Plague.\n\nDiscipline, Holy\nHalos verminderen de cooldown van uw Heilige Woord: Sereniteit en Heilig Woord: Heilig sec en Resonant Energie verhoogt bovendien de genezing van uw Heilige Woorden."}
MultiLanguageSpellData['nl'][1236399] = {name = "Priester Archon 11.2 Klasse Set 4pc", additional_info = "[q]Discipline, Shadow\nTerwijl Power Surge is actief, elke 2 casts van Devouring Plague voegt een andere Halo aan het effect bij effectiviteit, tijden.\n\nHeilige\nTerwijl Power Surge is actief, elke 2 casts van Heilig Woord: Sereniteit of Heilig Woord: Sancitify voegt een andere Halo aan het effect op effectiviteit, tijden."}
MultiLanguageSpellData['nl'][1236400] = {name = "Rogue Deathstalker 11.2 Klasse Set 2pc", additional_info = "[q]Assassinatie\nShiv verhoogt de effectiviteit van alle Deathstalker schade effecten en schade bonussen terwijl actief.\n\nOutlaw, Subtiliteit\nSymbolen van de dood verhoogt de effectiviteit van alle Deathstalker schade effecten en schade bonussen terwijl actief."}
MultiLanguageSpellData['nl'][1236401] = {name = "Rogue Deathstalker 11.2 Klasse Set 4pc", additional_info = "[q]Assassinatie\nShiv heeft 3 sec langere duur en verbruikt een toepassing van uw actieve Deathstalker's Mark wanneer geactiveerd.\n\nOutlaw, Subtiliteit\nSymbolen van de dood heeft 3 sec verlengd duur en verbruikt een toepassing van uw actieve Deathstalker's Mark wanneer geactiveerd."}
MultiLanguageSpellData['nl'][1236402] = {name = "Rogue Fatebound 11.2 Klasse Set 2pc", additional_info = "[q]Outlaw\nGhostly Strike dealt toegenomen schade en heeft 4 sec langere duur.\n\nEdge Case draait nu een extra Fatebound Coin en activeert Ghostly Strike activeert het effect.\n\nMoord, Subtiliteit\nKingsbane dealt toegenomen schade en heeft 4 sec langere duur.\n\nEdge Case draait nu een extra Fatebound Coin en activeert Kingsbane activeert zijn effect."}
MultiLanguageSpellData['nl'][1236403] = {name = "Rogue Fatebound 11.2 Klasse Set 4pc", additional_info = "[q]Outlaw\nMet een gelukkige Fatebound Coin vermindert de cooldown van Adrenaline Rush sec en Ghostly Strike sec.\n\nMoord, Subtiliteit\nMet een gelukkige Fatebound Coin vermindert de cooldown van Deathmark sec en Kingsbane sec."}
MultiLanguageSpellData['nl'][1236404] = {name = "Rogue Trickster 11.2 Klasse Set 2pc", additional_info = "[q]Unseen Blade dealt toegenomen schade en heeft een kans om twee keer toe te slaan."}
MultiLanguageSpellData['nl'][1236405] = {name = "Rogue Trickster 11.2 Klasse Set 4pc", additional_info = "[q]Coup de Grace kan nu worden geactiveerd een tweede keer binnen 5 sec, dealen% van de normale schade."}
MultiLanguageSpellData['nl'][1236406] = {name = "Shaman Farseer 11.2 Klasse Set 2pc", additional_info = "[q]Ancestral Swiftness roept een geautoriseerde Voorouder op die meer schade en genezing behandelt."}
MultiLanguageSpellData['nl'][1236407] = {name = "Shaman Farseer 11.2 Klasse Set 4pc", additional_info = "[q]Restoratie\nVoorouderlijke Snelheid verhoogt de schade en genezing van uw spreuken, vermindert de Mana kosten van uw spreuken, en verhoogt de oplaadsnelheid van Lava Burst en Riptide\n\nElementaire, verbetering\nVoorouderlijke Snelheid verhoogt de schade en genezing van uw spreuken, vermindert de Mana kosten van uw spreuken, en verhoogt de oplaadsnelheid van Lava Burst"}
MultiLanguageSpellData['nl'][1236408] = {name = "Sjamaan Stormbringer 11.2 Klasse Set 2pc", additional_info = "[q]Enhancement, Restauratie\nAscendance heeft de kans om een lading Tempest toe te kennen en elke 8 Ontwakende Stormen activeert nu Ascendance\n\nElementaal\nAscendance heeft de kans om een lading Tempest toe te kennen en elke 9 Ontwakende Stormen activeert nu Ascendance"}
MultiLanguageSpellData['nl'][1236409] = {name = "Shaman Stormbringer 11.2 Klasse Set 4pc", additional_info = "[q]Elemental, Restauratie\nNatuurschade verhoogd, en Ascendance machtigt uw volgende 2 Tempests om een storm boven te verzamelen die Natuurschade behandelt zijn primaire doel en verminderde schade aan nabijgelegen vijanden na 1,5 sec.\n\nVerbetering\nNatuurschade verhoogd, en Ascendance machtigt uw volgende 2 Tempests om een storm boven te verzamelen die Natuurschade behandelt zijn primaire doel en verminderde schade aan nabijgelegen vijanden na 1,5 sec."}
MultiLanguageSpellData['nl'][1236410] = {name = "Sjamaan Totemic 11.2 Klasse Set 2pc", additional_info = "[q]Elemental, Restauratie\nNadat u alle Whirling Element Motes verbruikt, werpt u Downpour op effectiviteit op de locatie van uw Susting Totem.\n\nVerbetering\nNadat u alle Whirling Element Motes heeft verbruikt, werpt uw Susting Totem Primordial Storm op effectiviteit op zijn locatie."}
MultiLanguageSpellData['nl'][1236411] = {name = "Sjamaan Totemic 11.2 Klasse Set 4pc", additional_info = "[q]Elemental, Restauratie\nNa het gieten van Downpon werpt uw volgende Chain Heelt, Healing Wave of Healing Surge opnieuw op effectiviteit.\n\nVerbetering\nNa het casten van Primordial Storm werpt uw volgende Lava Lash of Fire Nova opnieuw op effectiviteit."}
