MultiLanguageSpellData['nl'][1236417] = {name = "Warlock Diabolist 11.2 Klasse Set 2pc", additional_info = "[q]Vernietiging, Vernietiging\nCasting Chaos Bolt, Rain of Fire, of Shadowburn roept een Demonische Oculus, Consuming Demonische kunst flirt uw Demonische Oculi op uw huidige doel, exploderen voor Vuurschade en Vuurschade aan vijanden binnen bereik.\n\nDemonologie\nHand van Gul'dan cast op volle kracht roept een Demonische Oculus, Consuming Demonische Kunst flends uw Demonische Oculi op uw huidige doel, exploderen voor Vuurschade en Vuurschade aan vijanden binnen bereik."}
MultiLanguageSpellData['nl'][1236418] = {name = "Warlock Diabolist 11.2 Klasse Set 4pc", additional_info = "[q]Demonische Oculi analyseren de strijd terwijl actief en leveren informatie aan u als ze exploderen, het verhogen van uw Intellect"}
MultiLanguageSpellData['nl'][1236419] = {name = "Krijger Colossus 11.2 Klasse Set 2pc", additional_info = "[q]Demolish schade verhoogd en Critical Strike schade van uw vaardigheden wordt verhoogd met% op doelen beïnvloed door uw Demolish op basis van het aantal stapels Colossal Might geconsumeerd."}
