MultiLanguageSpellData['nl'][1236689] = {name = "Leegte verminderen", additional_info = "[q]Het nemen van schade heeft een hoge kans om ervoor te zorgen dat u de Essentie van nabijgelegen vijanden verslinden, dealen Schaduwschade splitsen tussen hen en u genezen van de schade behandeld.\n\nDodelijke schade niet hoger dan 18656 in plaats daarvan herstelt u gezondheid en reconstitueert u als onstabiele leegte Exceed gezondheid om te stabiliseren en te voorkomen dat de dood. Dit effect kan eenmaal per 8 minuten optreden. De Nucleus kan geen schade aanrichten tijdens het opladen."}
