MultiLanguageSpellData['nl'][1236792] = {name = "Essentie-bom", additional_info = "[q]Vernietiging\nHet consumeren van Essentie Burst tijdens Inner Flame vuurt een Essentie Bom op uw doel, schadelijke nabijgelegen vijanden voor Arcane, gereduceerd tot meer dan 5 doelen.\n\nBehoud, Augmentatie\nHet consumeren van Essentie Burst tijdens Inner Flame vuurt een Essentie Bom op uw doel, helende nabijgelegen bondgenoten voor, gereduceerd tot meer dan 5 doelen."}
