MultiLanguageSpellData['nl'][1245357] = {name = "Adorned Northeron Gryphon", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"De oudere gryphon renners en hoge sjamanen van de Northeron Wildhammer sierden vaak hun gryfons in sierlijke, veren-geklede stukken, wat hun rang en status aangeeft.\"\nHandelspost"}
MultiLanguageSpellData['nl'][1245358] = {name = "High Shaman's Aerie Gryphon", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"De oude Wildhammer sjamanen die voor het eerst gryphons tegenkwamen geloofden dat ze elementaire geesten in sterfelijke vorm waren. Deze ontmoeting zou voor eeuwig indrukken op de Wildhammer clan voor de komende generaties.\"\nHandelspost"}
MultiLanguageSpellData['nl'][1245359] = {name = "Cinder-Plumed Highland Gryphon", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Volgens de legende van Wildhammer wordt aangenomen dat het oranje verenkleed op gryphons een erfelijke eigenschap is die van hun elementaire voorouders is doorgegeven.\"\nHandelspost"}
