MultiLanguageSpellData['nl'][1245361] = {name = "Emberwing Sky Guide", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Vanuit de uitlopers van Khaz Modan, volgden we zijn door de zon verlichte vleugels - een in het noorden gebonden fakkel over de donkere zomerhemel.\" - De Pelgrimage van de Eerste Wildsage\nHandelspost"}
MultiLanguageSpellData['nl'][1245370] = {name = "Ornery Breezestider", additional_info = "[q]Summons en ontslaat uw Ornery Breezestider.\n[q]\"Deze talbuk is een koppige, koppige berg, zelfs na het leren kennen van zijn ruiter. Rijders pas op.\"\nHandelspost"}
