MultiLanguageSpellData['nl'][1248053] = {name = "Twilight Reflections", additional_info = "[q]Eternus roept alternatieve kwaadaardige partijleden op. Eternus roept kwaadaardige tijdlijn versies van spelers die proberen om Essentie te stelen. Als ze hun doel bereiken, werpen ze gestolen Essentie, verminderen maximale gezondheid, schade en genezing gedaan %\n\nDe onstabiele kopieën zijn voortdurend Unrravelling, lijden maximale gezondheid als Arcaneschade\n\nBij de dood, ze in plaats daarvan gegoten Merged Essentie en hun doel verhoogd maximale gezondheid, schade en genezing gedaan"}
