MultiLanguageSpellData['nl'][1250285] = {name = "Haaitest Crest-Horn", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"De Crest-Horn zal vaak worden aangetrokken om te grazen op de planten die groeien in de zee. Sommigen hebben de felste wilde dieren daar getrotseerd, waardoor ze echt Kalu'ak.\"\nHandelspost"}
MultiLanguageSpellData['nl'][1250287] = {name = "Floestrider Crest-Horn", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"De zelden geziene inwoner van de Azure Span wordt beschouwd als gezegend door de slagtand van de regio.\"\nHandelspost"}
MultiLanguageSpellData['nl'][1250288] = {name = "Cragstepper Crest-Horn", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Tuskaar zijn niet vaak te vinden op Highmountain, maar de kamdoorns komen vaak naar de kust om zeldzame lekkernijen te zoeken in de kustwateren.\"\nHandelspost"}
MultiLanguageSpellData['nl'][1250314] = {name = "Phantom Bloom", additional_info = "[q]Phantom Bloom zijn de Energie overblijfselen van inheemse K'areshi flora, onmogelijk te integreren in Algari recepten.\n\nIn plaats daarvan kunt u Phantom Bloom uitwisselen op de Resource Market for Algari materialen. Hun prijzen veranderen elke dag, dus geduld kan u helpen de beste deals!"}
MultiLanguageSpellData['nl'][1250317] = {name = "Lush Phantom Bloom", additional_info = "[q]Phantom Bloom zijn de Energie overblijfselen van inheemse K'areshi flora, onmogelijk te integreren in Algari recepten.\n\nIn plaats daarvan kunt u Phantom Bloom uitwisselen op de Resource Market for Algari materialen. Hun prijzen veranderen elke dag, dus geduld kan u helpen de beste deals!\n\nEnkele voorbeelden van Phantom Bloom zijn duidelijk groter dan verwacht. Ooit een van de weinige planten om de genadeloze afval van de K'aresh woestijnen te overleven, het was bekend om te gedijen in grotere rassen in de weelderige omgeving van de ongetemde bossen."}
