MultiLanguageSpellData['nl'][1250879] = {name = "Leystone Basilisk", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Deze prachtige basilisk wordt vaak opgejaagd voor de magische eigenschappen van zijn organen. Gelukkig voor de basilisk, de verbinding met leylijnen geeft het een prescient gevoel van het naderen van roofdieren.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1250880] = {name = "Felslate Basilisk", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Eenmaal gebruikelijk op de Broken Eilanden, werden felslate basilisks zwaar bejaagd door mijnwerkers die hun kostbare huiden zochten.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1250881] = {name = "Aquamarine Basilisk", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Ondanks hun naam, aquamarijn basilisks feest op een verscheidenheid van kustkristallen en oceanische rotsen.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1250882] = {name = "Illidari Dreadstalker", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Ondanks hun smaak voor vlees en onnatuurlijk vermogen om Vrees te ruiken, zijn deze mindere demonen gedomineerd door de Illidari zoals men een jachtgezel zou temmen.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1250884] = {name = "Illidari Blightstalker", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Deze demonen verslinden pest en genieten in verval. Wie dacht dat het een goed idee zou zijn om ze te berijden?\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1250886] = {name = "Highland Elderhorn", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"De huid van een hoogland vlierhoorn is ongelooflijk dik. Nooit in de geregistreerde geschiedenis heeft een hoogland vlierhoorn zelfs knipperen in reactie op beledigingen gegooid naar hen.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1250890] = {name = "Ensemble: Schouderbeschermers van de Afvallander Ziener", additional_info = "[q]Verzamel de verschijningen van de Untethered Seer's Vestiture Armor set."}
