MultiLanguageSpellData['nl'][1250915] = {name = "Timewarped Wyrmtongue", additional_info = "[q]Time-shifted in a wyrmtongue, genegeerd door de meeste vijanden.\nBeweging Speed toegenomen.\n\nIn staat om te zien Motes of Bronze op Argus: het verzamelen van Motes of Bronze zal verhogen uw beweging Speed en Bronze winsten, stapelen totdat dit effect is uitgewerkt.\n\nGevecht annuleert dit effect."}
