MultiLanguageSpellData['nl'][1251045] = {name = "Arrest van de Vindicator", additional_info = "[q]Artifact vermogen\n\nWord Licht vergeten en roep een straal van hemels licht dat doelen volgt, dealen tot [( Attack/Spell Power)] Heilige schade aan vijanden en helende vriendelijke doelen voor [( Attack/Spell Power)] binnen zijn gebied. Behandelt verminderde schade en genezing boven 5 doelen.\n\nLichtgesmeed\nGeeft je artefact zijn andere lichteigenschappen."}
