MultiLanguageSpellData['nl'][1251255] = {name = "Treetop Highmountain Eagle", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"De majestueuze adelaar is een symbool van trots voor de hoogbergenstammen. Dit grote beest's vermogen om tauren op hun rug te dragen spreekt tot de pure Strength en de grootte van de wezens van High Mountain.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251257] = {name = "Leyfrost Manasaber", additional_info = "[q]Summons en ontslaat deze berg."}
MultiLanguageSpellData['nl'][1251259] = {name = "Toevoegen Keystone Affix: Tyrannisch versterkt", additional_info = "[q]Voeg het Tyrannisch versterkte affix toe aan een Mythic Keystone."}
MultiLanguageSpellData['nl'][1251264] = {name = "Nightwell Manasaber", additional_info = "[q]Summons en ontslaat deze berg."}
MultiLanguageSpellData['nl'][1251265] = {name = "Arcberry Manasaber", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Genoemd naar hun gelijkenis met de heldere bessen gemaakt tot arckine, deze trotse katten hebben een scherp bewustzijn van de leylijnen die onder hen.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251266] = {name = "Droombolt", additional_info = "[q]Hurl aarde op een vijand dealen Fysieke schade."}
MultiLanguageSpellData['nl'][1251279] = {name = "Fel-Scarred Mana Ray", additional_info = "[q]Summons en ontslaat een Fel-Scarred Mana Ray. Deze mount verandert afhankelijk van uw rijvaardigheid en locatie.\n[q]\"Overleven op Argus is geen gemakkelijke taak. Zijn leerachtige huid littekens door fel corruptie, deze Mana straal is gevoelig voor aanvallen, meer dan gebruikelijk.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251281] = {name = "Bloedtand Mana Ray", additional_info = "[q]Summons en ontslaat een Bloodtooth Mana Ray. Deze mount verandert afhankelijk van uw rijvaardigheid en locatie.\n[q]\"De verbrijzeling van Argus dreef dit ras van Mana straal tot bloeddorstig. Het bevindt zich nu op het corrupte bloed van alle wezens waar het zijn vele tanden in kan laten zinken.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251283] = {name = "Albino Mana Ray", additional_info = "[q]Summons en ontslaat een Albino Mana Ray. Deze mount verandert afhankelijk van uw rijvaardigheid en locatie.\n[q]\"De verbrijzeling van Argus zorgde ervoor dat de Mana stralen muteren en zich aanpassen aan hun omgeving. Sommigen lieten hun pigmenten achter om hun zintuigen te versterken.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251284] = {name = "Lichte Mana-straal", additional_info = "[q]Summons en ontslaat een Luminous Mana Ray. Deze mount verandert afhankelijk van uw rijvaardigheid en locatie.\n[q]\"Mana stralen kunnen een heldere gloed uitstralen om prooi te lokken.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251292] = {name = "Plaatsing", additional_info = nil}
MultiLanguageSpellData['nl'][1251295] = {name = "Twilight Courser", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Om roofdieren te ontlopen, verduistert deze cursus zijn hoorn terwijl hij zich verbergt en flitst met schitterende stralen wanneer hij wordt uitgelokt.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251297] = {name = "Golden Sunrunner", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Deze vrije geest geniet van lange draf op het strand en folkelend door gevarieerde bloemenvelden.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251298] = {name = "Turquoise Courser", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Genoemd naar haar uniek gekleurde ogen die lijken te doordringen van uw ziel, de turquoise cursusler toont meer intelligentie dan haar droomrunner neven en staat bekend als een uitstekende beoordeling van het karakter.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251300] = {name = "Gloomdark Nachtmerrie", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Aangeraakt door de Emerald Nightmare, is de aanwezigheid van dit wezen in zijn dromen een voorteken van ongeluk. Om er een te zien terwijl wakker een absolute catastrofe voorspelt.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251305] = {name = "Bonesteed of Triumph", additional_info = "[q]Summons en ontslaat deze berg.\nEen goed oorlogspaard is loyaal aan zijn botten. Na zijn sterfelijke spiraal te hebben afgeschud, is dit paard een voorteken van gedurfde verovering.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251307] = {name = "Bonesteed of Bloodshed", additional_info = "[q]Summons en ontslaat deze berg.\nEen goed oorlogspaard is loyaal aan zijn botten. Dit paard is een voorteken van eeuwige strijd.\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251309] = {name = "Bonesteed of Plague", additional_info = "[q]Summons en ontslaat deze berg.\nEen goed oorlogspaard is loyaal aan zijn botten. Na het afschudden van zijn sterfelijke spiraal, is dit paard een voorteken van ziekte en lijden.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251311] = {name = "Bonesteed of Oblivion", additional_info = "[q]Summons en ontslaat deze berg.\nEen goed oorlogspaard is loyaal aan zijn botten. Dit paard is een voorteken van schaarste en dood.\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251312] = {name = "Verzamelen", additional_info = nil}
