MultiLanguageSpellData['nl'][1251325] = {name = "Plaatsing", additional_info = nil}
MultiLanguageSpellData['nl'][1251327] = {name = "WASHovelLoop kanaliseren w/ Shovel", additional_info = nil}
MultiLanguageSpellData['nl'][1251395] = {name = "Illusie: Sha Corruptie", additional_info = "[q]Verzamel het wapen betovering verschijning van Sha Corruptie."}
MultiLanguageSpellData['nl'][1251396] = {name = "Longhorned Sable Talbuk", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"De talkbuks van Argus zijn gegroeid lange, grove vacht van briljante kleuren die de tinten van hun gebroken planeet weerspiegelt.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251397] = {name = "Garnet Ruinstrider", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Uitgerust met stevige barden, dragen Argussiaanse ruïneriders zonder angst hun ruiters over het gebroken afval van Argus en daarbuiten.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251398] = {name = "Longhorned Bleakhoof Talbuk", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Gesneeuwd door de chaos veroorzaakt door tientallen jaren conflict, is dit fel-infused paard een perfecte match voor een onverschrokken avonturier.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251399] = {name = "Longhorned Argussian Talbuk", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Veel talbuks wisten ongedeerd te blijven ondanks de exploitatie van hun thuiswereld door het Legioen. Hun vasthoudendheid past bij een edel paard.\"\nWereldevenement:\nWoW Remix: Legioen"}
MultiLanguageSpellData['nl'][1251400] = {name = "Longhorned Beryl Talbuk", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"Deze wilde talbuk gevonden tussen de ruïnes van Argus heeft overleefd en volhard door decennia van strijd.\"\nWereldevenement:\nWoW Remix: Legioen"}
