MultiLanguageSpellData['nl'][1252024] = {name = "Dryad's favor", additional_info = "[q]Balance, Feral, Guardian\nWanneer uw Dryad vervaagt, uw volgende 2 Starsurges schade voor een extra bedrag gelijk aan uw schade gedaan terwijl het actief was en splash van hun schade op nabijgelegen vijanden, gereduceerd tot meer dan 5 doelen.\n\nHerstel\nWanneer uw Dryad vervaagt, uw volgende 2 Swiftmends Heelt voor een extra bedrag gelijk aan uw genezing gedaan terwijl het actief was en splash van hun genezing op nabijgelegen bondgenoten, gereduceerd tot meer dan 5 doelen."}
