MultiLanguageSpellData['nl'][1252185] = {name = "Infusie pylonen", additional_info = "[q]De arcane pylons van de kamer pompen Energie in Loom'ithar door arcane balken, waardoor een overtollig Nova op contact.\n\nSpelers staan binnen de straal blokkeren zijn pad, lijden Arcaneschade en het verkrijgen van een toepassing van Hyper Infusie Dit effect stacks."}
MultiLanguageSpellData['nl'][1252190] = {name = "Vlucht van de Val'kyr", additional_info = "[q]Vindicator's Oordeel zegent nabijgelegen bondgenoten te worden bewaakt door val'kyr\n\nTerwijl bewaakt, fatale aanvallen in plaats daarvan worden onderschept door de val'kyr en Heelt het doel om hun maximale gezondheid. Kan niet activeren op hetzelfde doel vaker dan één keer per 8 min."}
