MultiLanguageSpellData['nl'][1255154] = {name = "Afsluiten catch up", additional_info = "FA00Als u verdwaald bent, probeer dan Peruse Tome te teleporteren naar het juiste gebied.\n\nHet verlaten van Catch Up zal teleporteren u Back naar uw hoofdstad. U zult in staat zijn om deze Catch Up Campaign opnieuw te hervatten op elk moment, tenzij u een andere start.\n\nWilt u doorgaan?"}
