MultiLanguageSpellData['nl'][1255159] = {name = "Mechanisch Prototype Panther MK-0", additional_info = "[q]Summons en ontslaat deze berg.\n\"Toen Gadgetzan burgers het ondergrondse lab van het Gazlowe paleis openden, stikten de gebrul van gekooide beesten. Ondermijn tech gevechtsmodules op deze panters, waardoor bovenmenselijke Strength en Speed. Rustbolt ingenieurs herprogrammeerden ze uitsluitend voor krijgers die campagne voeren in K'aresh. Vergeet niet om modules te ruilen op het Morphing Forum voor de implementatie.\"\nIn-Game Shop"}
MultiLanguageSpellData['nl'][1255165] = {name = "Raadpleeg de Tome", additional_info = "[q]Query de Tome over waar te gaan volgende of voor meer informatie."}
MultiLanguageSpellData['nl'][1255179] = {name = "Staal Prototype Panther MK-0", additional_info = "[q]Summons en ontslaat deze berg.\n[q]\"De eerste Steel Horde soldaten over de Dark Portal gevangen een woeste nachtzwaard. Blackrock artisanalisten bewapenden het met magma Armor en transformeerden het in een gevechtswapen. Krijgers kunnen haar onderdelen aanpassen op het Morphing Forum om hun vechtstijl aan te passen en het slagveld te domineren.\"\nIn-Game Shop"}
